      </div>
    </Modal>
  );
}

// ─── Reason Modal ─────────────────────────────────────────────────────────────
function ReasonModal({ title, placeholder, onConfirm, onClose, loading }) {
  const [reason, setReason] = useState('');
  return (
    <Modal title={title} onClose={onClose}>
      <div className="form-group">
        <label className="form-label required">Reason</label>
        <textarea className="form-textarea" value={reason} onChange={e => setReason(e.target.value)} placeholder={placeholder} rows={3} />
      </div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
        <button className="btn btn-ghost" onClick={onClose} disabled={loading}>Back</button>
        <button className="btn btn-primary" onClick={() => reason.trim() && onConfirm(reason.trim())}
          disabled={loading || !reason.trim()}>
          {loading ? <InlineSpinner /> : 'Confirm'}
        </button>
      </div>
    </Modal>
  );
}

// ─── Main Page ────────────────────────────────────────────────────────────────
export default function LeavePage() {
  const { user } = useAuth();
  const roleStr  = (user?.role || user?.Role || '').toLowerCase();
  const isManager    = roleStr.includes('manager') || roleStr.includes('hr') || roleStr.includes('admin') || roleStr === 'supervisor';
  const isHRManager  = roleStr.includes('hr');

  const [tab,            setTab]            = useState('dashboard');
  const [showAdjustModal,setShowAdjustModal] = useState(false);
  const [showEditModal,  setShowEditModal]   = useState(null);   // req object
  const [balances,       setBalances]        = useState([]);
  const [myRequests,     setMyReqs]          = useState([]);
  const [allRequests,    setAll]             = useState([]);
  const [leaveTypes,     setTypes]           = useState([]);
  const [holidays,       setHolidays]        = useState([]);
  const [loadBal,        setLoadBal]         = useState(true);
  const [loadReq,        setLoadReq]         = useState(true);
  const [loadAll,        setLoadAll]         = useState(true);
  const [submitting,     setSubmitting]      = useState(false);
  const [editLoading,    setEditLoading]     = useState(false);
  const [historyFilter,  setHistoryFilter]   = useState('');
  const [allFilter,      setAllFilter]       = useState('');
  const [searchQuery,    setSearchQuery]     = useState('');
  const [reasonModal,    setReasonModal]     = useState(null);
  const [actingReason,   setActingReason]    = useState(false);

  // Local notification state (LV-019, LV-024)
  const [notifications, setNotifications] = useState([
    { message: 'Your Annual Leave request has been approved', time: '2 hours ago', read: false },
    { message: 'Ahmed Khalil submitted a leave request pending your approval', time: '5 hours ago', read: false },
    { message: 'Medical verification required for LV-2024-089', time: 'Yesterday', read: true },
  ]);

  const loadData = useCallback(async () => {
    setLoadBal(true); setLoadReq(true);
    leaveAPI.getMyBalances()
      .then(r => setBalances(Array.isArray(r.data) ? r.data : []))
      .catch(console.error).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests({ limit: 100 })
      .then(r => setMyReqs(Array.isArray(r.data) ? r.data : []))
      .catch(console.error).finally(() => setLoadReq(false));
    leaveAPI.getTypes()
      .then(r => setTypes(Array.isArray(r.data) ? r.data : []))
      .catch(console.error);
    leaveAPI.getHolidays()
      .then(r => setHolidays(Array.isArray(r.data) ? r.data : []))
      .catch(console.error);
    if (isManager) {
      setLoadAll(true);
      leaveAPI.listAll({ limit: 200 })
        .then(r => setAll(Array.isArray(r.data) ? r.data : []))
        .catch(console.error).finally(() => setLoadAll(false));
    } else { setLoadAll(false); }
  }, [isManager]);

  useEffect(() => { loadData(); }, [loadData]);

  // ── Actions ─────────────────────────────────────────────────────────────────
  const handleSubmit = async (form) => {
    setSubmitting(true);
    try {
      await leaveAPI.submit(form);
      toast.success('Leave request submitted!');
      setNotifications(n => [{ message: 'Your leave request has been submitted', time: 'Just now', read: false }, ...n]);
      setTab('history');
      setTimeout(loadData, 100);
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to submit request'); }
    finally { setSubmitting(false); }
  };

  const handleAction = async (id, action, reason) => {
    try {
      if (action === 'cancel') {
        if (!reason) { setReasonModal({ id, action: 'cancel' }); return; }
        await leaveAPI.cancel(id, { CancelReason: reason });
        toast.success('Request cancelled');
      } else if (action === 'approve') {
        await leaveAPI.approveReject(id, { decision: 'Approved', comments: '' });
        toast.success('Request approved');
        setNotifications(n => [{ message: `Request #${id} approved`, time: 'Just now', read: false }, ...n]);
      } else if (action === 'reject') {
        if (!reason) { setReasonModal({ id, action: 'reject' }); return; }
        await leaveAPI.approveReject(id, { decision: 'Rejected', comments: reason });
        toast.success('Request rejected');
      }
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Action failed'); }
  };

  // LV-017 — Edit / Modify request
  const handleEdit = (req) => setShowEditModal(req);
  const handleSaveEdit = async (form) => {
    if (!showEditModal) return;
    setEditLoading(true);
    const id = showEditModal.LeaveRequestID || showEditModal.leaveRequestId || showEditModal.id;
    try {
      await leaveAPI.updateRequest(id, {
        StartDate: form.startDate,
        EndDate:   form.endDate,
        Reason:    form.reason,
        DocumentReference: form.documentReference,
        ...(form.LeaveTypeID ? { LeaveTypeID: parseInt(form.LeaveTypeID, 10) } : {}),
      });
      toast.success('Request updated');
      setShowEditModal(null);
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Update failed'); }
    finally { setEditLoading(false); }
  };

  // LV-026 — Override
  const handleOverride = async (requestId, newStatus, reason) => {
    try {
      await leaveAPI.approveReject(requestId, { decision: newStatus === 'APPROVED' ? 'Approved' : 'Rejected', comments: `[HR Override] ${reason}` });
      toast.success('Override applied');
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Override failed'); }
  };

  // LV-044 — Payroll sync
  const handlePayrollSync = async () => {
    if (leaveAPI.syncPayroll) await leaveAPI.syncPayroll();
    else await new Promise(r => setTimeout(r, 800)); // mock
  };

  const handleReasonConfirm = async (reason) => {
    if (!reasonModal) return;
    setActingReason(true);
    try { await handleAction(reasonModal.id, reasonModal.action, reason); setReasonModal(null); }
    finally { setActingReason(false); }
  };

  // ── Filtered data ────────────────────────────────────────────────────────────
  const filteredMyReqs  = myRequests.filter(r => statusMatches(r.Status || r.status, historyFilter));
  const filteredAllReqs = allRequests.filter(r => {
    const matchStatus = statusMatches(r.Status || r.status, allFilter);
    const matchSearch = !searchQuery || (r.employeeName || r.Employee?.FullName || '').toLowerCase().includes(searchQuery.toLowerCase());
    return matchStatus && matchSearch;
  });

  const TABS = [
    { id: 'dashboard', label: 'Dashboard', icon: BarChart2 },
    { id: 'request',   label: 'Request Leave', icon: Plus },
    { id: 'history',   label: 'My History', icon: Clock },
    ...(isManager ? [
      { id: 'all',      label: 'All Requests', icon: Calendar },
      { id: 'calendar', label: 'Team Calendar', icon: CalendarDays },
      ...(isHRManager ? [
        { id: 'hr',     label: 'HR Tools', icon: Settings },
      ] : []),
    ] : []),
  ];

  return (
    <>
      {/* Modals */}
      {reasonModal && (
        <ReasonModal
          title={reasonModal.action === 'cancel' ? 'Cancel Leave Request' : 'Reject Leave Request'}
          placeholder={reasonModal.action === 'cancel' ? 'Reason for cancellation…' : 'Reason for rejection…'}
          onConfirm={handleReasonConfirm}
          onClose={() => setReasonModal(null)}
          loading={actingReason}
        />
      )}
      {showAdjustModal && <AdjustBalanceModal onClose={() => setShowAdjustModal(false)} />}
      {showEditModal && (
        <EditRequestModal
          req={showEditModal}
          leaveTypes={leaveTypes}
          onSave={handleSaveEdit}
          onClose={() => setShowEditModal(null)}
          loading={editLoading}
        />
      )}

      {/* Page Header */}
      <div className="page-header flex justify-between items-center">
        <div>
          <h1>Leave Management</h1>
          <p>Manage leave requests, balances, and approvals</p>
        </div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <NotificationBell
            notifications={notifications}
            onMarkRead={() => setNotifications(n => n.map(x => ({ ...x, read: true })))}
          />
          {isManager && (
            <button className="btn btn-primary" onClick={() => setShowAdjustModal(true)}>
              Adjust Balance
            </button>
          )}
        </div>
      </div>

      {/* Tabs */}
      <div className="tabs">
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}>
            <Icon size={14} style={{ marginRight: 6, verticalAlign: 'middle' }} />{label}
          </button>
        ))}
      </div>

      {/* ── Dashboard ── */}
      {tab === 'dashboard' && (
        <>
          {/* LV-032 — leave balances */}
          <div className="grid-4" style={{ marginBottom: 28 }}>
            {loadBal
              ? [1,2,3,4].map(i => <SkeletonCard key={i} />)
              : balances.length > 0
                ? balances.slice(0, 4).map((b, i) => <BalanceCard key={i} balance={b} loading={false} />)
                : (
                  <div style={{ gridColumn: '1 / -1', textAlign: 'center', padding: '32px 20px', color: 'var(--text-muted)', background: 'var(--surface)', borderRadius: 'var(--radius-lg)' }}>
                    <CalendarDays size={32} style={{ opacity: 0.3, marginBottom: 10 }} />
                    <div style={{ fontWeight: 500 }}>No leave balances found</div>
                    <div style={{ fontSize: '0.8rem', marginTop: 4 }}>Contact HR to initialize your leave balance for this year.</div>
                  </div>
                )
            }
          </div>

          <div className="grid-2">
            {/* Pending requests */}
            <div className="card">
              <div className="card-header">
                <div className="card-title">Pending Requests</div>
                <span className="badge badge-pending">
                  {myRequests.filter(r => ['Pending','PENDING_MANAGER','PENDING_HR','SUBMITTED'].includes(r.status || r.Status)).length}
                </span>
              </div>
              {myRequests.filter(r => ['Pending','PENDING_MANAGER','PENDING_HR','SUBMITTED'].includes(r.status || r.Status)).length === 0
                ? <div style={{ textAlign: 'center', padding: 30, color: 'var(--text-muted)', fontSize: '0.85rem' }}>No pending requests</div>
                : myRequests.filter(r => ['Pending','PENDING_MANAGER','PENDING_HR','SUBMITTED'].includes(r.status || r.Status)).map((req, i) => {
                    const name = req.leaveTypeName || req.LeaveTypeName || req.leaveType?.LeaveTypeName || '—';
                    const days = req.numberOfDays ?? req.TotalDays ?? req.totalDays ?? req.days ?? '—';
                    const from = (req.startDate || req.StartDate) ? new Date(req.startDate || req.StartDate).toLocaleDateString() : '—';
                    const to   = (req.endDate   || req.EndDate)   ? new Date(req.endDate   || req.EndDate).toLocaleDateString()   : '—';
                    return (
                      <div key={i} style={{ padding: '12px 0', borderBottom: '1px solid var(--border-light)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
                          <div style={{ fontWeight: 500, fontSize: '0.9rem' }}>{name}</div>
                          <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{from} — {to}</div>
                        </div>
                        <div style={{ textAlign: 'right' }}>
                          <div style={{ fontWeight: 600 }}>{days !== '—' ? `${days} days` : '—'}</div>
                          <Badge status="Pending">Pending</Badge>
                        </div>
                      </div>
                    );
                  })
              }
            </div>

            {/* Upcoming holidays */}
            <div className="card">
              <div className="card-header"><div className="card-title">Upcoming Holidays</div></div>
              {holidays.length === 0
                ? <div style={{ textAlign: 'center', padding: 30, color: 'var(--text-muted)', fontSize: '0.85rem' }}>No holidays scheduled</div>
                : holidays.filter(h => new Date(h.HolidayDate || h.holidayDate || h.date) >= new Date()).slice(0, 6).map((h, i) => (
                    <div key={i} style={{ padding: '10px 0', borderBottom: '1px solid var(--border-light)', display: 'flex', justifyContent: 'space-between' }}>
                      <div>
                        <div style={{ fontWeight: 500, fontSize: '0.875rem' }}>{h.HolidayName || h.holidayName || h.name}</div>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Public Holiday</div>
                      </div>
                      <div style={{ fontSize: '0.8rem', color: 'var(--gold)', fontWeight: 600 }}>
                        {(h.HolidayDate || h.holidayDate || h.date) ? new Date(h.HolidayDate || h.holidayDate || h.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : '—'}
                      </div>
                    </div>
                  ))
              }
            </div>
          </div>
        </>
      )}

      {/* ── Request Leave ── */}
      {tab === 'request' && (
        <div style={{ maxWidth: 600 }}>
          <div className="card">
            <div className="card-header">
              <div>
                <div className="card-title">Submit Leave Request</div>
                <div className="card-subtitle">Fill in the details below to request time off</div>
              </div>
            </div>
            {leaveTypes.length === 0 && (
              <div style={{ padding: '10px 14px', marginBottom: 12, background: 'rgba(240,180,41,0.08)', borderRadius: 'var(--radius-md)', fontSize: '0.82rem', color: 'var(--text-secondary)' }}>
                <AlertCircle size={13} style={{ marginRight: 6, verticalAlign: 'middle' }} />
                No leave types available. Contact HR to configure leave types.
              </div>
            )}
            <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmit} loading={submitting} />
          </div>
        </div>
      )}

      {/* ── My History (LV-033, LV-034) ── */}
      {tab === 'history' && (
        <>
          <div className="filter-bar">
            {STATUS_OPTIONS.map(({ value, label }) => (
              <button key={value} className={`filter-chip ${historyFilter === value ? 'active' : ''}`} onClick={() => setHistoryFilter(value)}>
                {label}
              </button>
            ))}
          </div>
          {loadReq ? <SkeletonCard /> : filteredMyReqs.length === 0
            ? <div className="card"><div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-muted)' }}>No leave requests found</div></div>
            : (
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Leave Type</th>
                      <th>Period</th>
                      <th>Days</th>
                      <th>Status</th>
                      <th>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredMyReqs.map((req, i) => (
                      <RequestRow key={req.LeaveRequestID || req.leaveRequestId || req.id || i}
                        req={req} onAction={handleAction} onEdit={handleEdit} isManager={false} userRole={user?.role} />
                    ))}
                  </tbody>
                </table>
              </div>
            )
          }
        </>
      )}

      {/* ── All Requests (LV-020–022, LV-035–040) ── */}
      {tab === 'all' && isManager && (
        <>
          {/* Search + filter bar */}
          <div style={{ display: 'flex', gap: 12, marginBottom: 12, flexWrap: 'wrap', alignItems: 'center' }}>
            <div style={{ position: 'relative', flex: '0 0 220px' }}>
              <Search size={13} style={{ position: 'absolute', left: 10, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
              <input className="form-input" type="text" placeholder="Search employee…" value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                style={{ paddingLeft: 30, fontSize: '0.82rem' }} />
            </div>
            <div className="filter-bar" style={{ margin: 0 }}>
              {STATUS_OPTIONS.map(({ value, label }) => (
                <button key={value} className={`filter-chip ${allFilter === value ? 'active' : ''}`} onClick={() => setAllFilter(value)}>
                  {label}
                </button>
              ))}
            </div>
          </div>

          {/* Manager delegation panel */}
          {!isHRManager && <DelegationPanel />}

          {/* Pattern alerts (LV-037–040) */}
          <LeavePatternAlerts requests={allRequests} />

          {loadAll ? <SkeletonCard /> : filteredAllReqs.length === 0
            ? <div className="card"><div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--text-muted)' }}>{allFilter ? `No ${allFilter.toLowerCase()} requests found` : 'No leave requests found'}</div></div>
            : (
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Leave Type</th>
                      <th>Employee</th>
                      <th>Period</th>
                      <th>Days</th>
                      <th>Status</th>
                      <th>Reason</th>
                      <th>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredAllReqs.map((req, i) => (
                      <RequestRow key={req.LeaveRequestID || req.id || i}
                        req={req} onAction={handleAction} onEdit={handleEdit} isManager={true} userRole={user?.role} />
                    ))}
                  </tbody>
                </table>
              </div>
            )
          }
        </>
      )}

      {/* ── Team Calendar (LV-035) ── */}
      {tab === 'calendar' && isManager && (
        <TeamLeaveCalendar teamLeaves={allRequests.filter(r => normStatus(r.Status || r.status) === 'APPROVED')} />
      )}

      {/* ── HR Tools (LV-025–030, LV-041–044) ── */}
      {tab === 'hr' && isHRManager && (
        <>
          {/* LV-044 — Payroll sync */}
          <PayrollSyncPanel onSync={handlePayrollSync} />

          {/* LV-041–043 — Accrual & Carry-Forward */}
          <AccrualPanel balances={balances} onAdjust={() => setShowAdjustModal(true)} />

          {/* LV-026 — Override */}
          <OverridePanel requests={allRequests} onOverride={handleOverride} />

          {/* LV-027 — Bulk approval teaser */}
          <div className="card">
            <div className="card-header">
              <div className="card-title"><Layers size={15} style={{ marginRight: 6 }} />Bulk Process Requests</div>
            </div>
            <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
              Select multiple requests from the "All Requests" tab to bulk approve or reject. You can also filter by type or date range before selecting.
            </p>
            <button className="btn btn-primary btn-sm" onClick={() => setTab('all')}>
              Go to All Requests →
            </button>
          </div>

          {/* LV-030 — Notify on finalization */}
          <div className="card" style={{ marginTop: 16 }}>
            <div className="card-header">
              <div className="card-title"><Bell size={15} style={{ marginRight: 6 }} />Stakeholder Notifications</div>
            </div>
            <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
              Configure automatic notification rules sent to employees, managers, and payroll on leave finalization.
            </p>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {[
                { label: 'Notify employee on approval/rejection', defaultChecked: true },
                { label: 'Notify manager on final HR decision', defaultChecked: true },
                { label: 'Notify payroll on approved leave', defaultChecked: true },
                { label: 'Send daily digest to HR Manager', defaultChecked: false },
              ].map((n, i) => (
                <label key={i} style={{ display: 'flex', alignItems: 'center', gap: 10, fontSize: '0.875rem', cursor: 'pointer' }}>
                  <input type="checkbox" defaultChecked={n.defaultChecked} onChange={() => toast.success('Preference saved')} />
                  {n.label}
                </label>
              ))}
            </div>
          </div>
        </>
      )}
    </>
  );
}
